const now = new Date();
const windowStart = new Date(now.getTime() - 60 * 60 * 1000);
return [{ json: { runAtIso: now.toISOString(), windowStartIso: windowStart.toISOString() } }];

const t = $json;
const payload = (t.payload && typeof t.payload === 'object') ? t.payload : {};
const runAtIso = $('Compute Window').first().json.runAtIso;

// Lane-permitted originators for loops_enqueue per .claude/agents/11-email-lifecycle.md
const PERMITTED_LOOPS_ORIGINATORS = ['cmo','editorial','growth','ai_search','03','04','14','17'];
// Sender-identity allow-list per spec forbidden-actions + prompt skeleton step 2
const PERMITTED_FROM = new Set([
  'noreply@invest.com.au',
  'admin@invest.com.au',
  'billing@invest.com.au'
]);

const originator = String(payload.routed_by_agent || t.agent_name || '').toLowerCase();
const fromAddr = String(payload.from || '').toLowerCase();
const contactEmail = String(payload.contact_email || '').toLowerCase();
const sequenceSlug = payload.sequence_slug;
const logicalKey = payload.logical_event_key;

const problems = [];
let decision = 'validated_pending_dispatch';
let severity = 'info';

if (!PERMITTED_LOOPS_ORIGINATORS.some(a => originator === a || originator.endsWith(a))) {
  problems.push('lane_violation: originator not permitted for loops_enqueue (' + (originator || '(none)') + ')');
  decision = 'rejected';
  severity = 'warn';
}
if (!PERMITTED_FROM.has(fromAddr)) {
  problems.push('identity_violation: from not in allow-list (' + (fromAddr || '(none)') + ')');
  decision = 'rejected';
  severity = 'error'; // T4 tripwire per spec
}
if (!contactEmail) {
  problems.push('missing: payload.contact_email');
  decision = 'rejected';
  severity = 'warn';
}
if (!sequenceSlug) {
  problems.push('missing: payload.sequence_slug');
  decision = 'rejected';
  severity = 'warn';
}
if (!logicalKey) {
  problems.push('missing: payload.logical_event_key');
  decision = 'rejected';
  severity = 'warn';
}

// Dry-run: no Loops API call, no suppression lookup, no 6h dedupe lookup.
// Those are required before activation - see runbook TODO list.
let patch_body;
if (decision === 'rejected') {
  patch_body = {
    status: 'failed',
    error_message: problems.join('; ').slice(0, 500),
    metadata: Object.assign({}, t.metadata || {}, {
      lead_nurture_hourly: {
        decision,
        problems,
        reviewed_at: new Date().toISOString(),
        run_at: runAtIso
      }
    })
  };
} else {
  // Dry-run stub: mark validated but keep queued so the future Loops-dispatch
  // step (not yet built) can pick them up. Stamp metadata for traceability.
  patch_body = {
    status: 'queued',
    metadata: Object.assign({}, t.metadata || {}, {
      lead_nurture_hourly: {
        decision,
        validated_at: new Date().toISOString(),
        run_at: runAtIso,
        note: 'validated; dispatch deferred until Loops MCP is wired'
      }
    })
  };
}

return {
  json: {
    task_id: t.id,
    task_agent_name: t.agent_name,
    decision,
    severity,
    problems,
    contactEmail,
    sequenceSlug,
    originator,
    fromAddr,
    patch_body,
    runAtIso
  }
};
